/**
 * Fetch problems with optional filters for difficulty, tags, and limit.
 * Supports case-insensitive tag filtering with tags passed as comma-separated string or array.
 * Returns problems sorted by stable criteria and metadata including normalized tags.
 *
 * @param {Object} params
 * @param {string|Array<string>} [params.tags] - Tags to filter by (case-insensitive).
 * @param {string} [params.difficulty] - Difficulty filter.
 * @param {number} [params.limit] - Limit on number of problems returned.
 * @returns {Promise<{problems: Array, metadata: {tags: Array<string>}}>} Filtered problems and metadata.
 */
async function getProblems({ tags, difficulty, limit } = {}) {
  // Normalize tags input to array of lowercase strings
  let normalizedTags = [];
  if (tags) {
    if (Array.isArray(tags)) {
      normalizedTags = tags
        .filter(t => typeof t === 'string')
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    } else if (typeof tags === 'string') {
      normalizedTags = tags
        .split(',')
        .map(t => t.trim().toLowerCase())
        .filter(t => t.length > 0);
    }
  }

  // Base query
  let query = db('problems');

  // Apply difficulty filter if provided
  if (difficulty) {
    query = query.where('difficulty', difficulty);
  }

  // Apply tag filtering if tags provided
  if (normalizedTags.length > 0) {
    // We assume problems have a 'tags' column which is an array of strings
    // We want problems that have ALL of the requested tags (AND semantics)
    // Use case-insensitive matching by lowercasing tags in DB and comparing
    // This requires raw SQL or knex whereRaw depending on DB

    // For Postgres, we can use array operators and unnest with lower
    // But to keep it simple and portable, filter in JS after fetching all filtered by difficulty
    // However, that is inefficient. Instead, use a whereRaw with ILIKE ANY

    // We'll do a whereRaw with EXISTS for each tag
    normalizedTags.forEach(tag => {
      query = query.whereRaw("EXISTS (SELECT 1 FROM unnest(tags) t WHERE lower(t) = ?)", [tag]);
    });
  }

  // Apply stable sorting: by difficulty asc, then by problemId asc
  query = query.orderBy('difficulty', 'asc').orderBy('problemId', 'asc');

  // Apply limit if provided
  if (limit && Number.isInteger(limit) && limit > 0) {
    query = query.limit(limit);
  }

  // Execute query
  const problems = await query.select();

  // Compose metadata with normalized tags filter
  const metadata = {
    tags: normalizedTags
  };

  return { problems, metadata };
}

module.exports = {
  getProblems
};
